{%- set source_and_derived_column_names = (all_source_columns + derived_column_names) | unique | list -%}

{%- set source_columns_to_select = automate_dv.process_columns_to_select(all_source_columns, exclude_column_names) -%}
{%- set derived_columns_to_select = automate_dv.process_columns_to_select(source_and_derived_column_names, null_column_names + hashed_column_names) | unique | list -%}
{%- set derived_and_null_columns_to_select = automate_dv.process_columns_to_select(source_and_derived_column_names + null_column_names, hashed_column_names) | unique | list -%}
{%- set final_columns_to_select = [] -%}

{#- Include source columns in final column selection if true -#}
{%- if include_source_columns -%}
    {%- if automate_dv.is_nothing(derived_columns)
           and automate_dv.is_nothing(null_columns)
           and automate_dv.is_nothing(hashed_columns)
           and automate_dv.is_nothing(ranked_columns) -%}
        {%- set final_columns_to_select = final_columns_to_select + all_source_columns -%}
    {%- else -%}
        {#- Only include non-overriden columns if not just source columns -#}
        {%- set final_columns_to_select = final_columns_to_select + source_columns_to_select -%}
    {%- endif -%}
{%- endif %}

WITH source_data AS (

    SELECT

    {{- "\n\n    " ~ automate_dv.print_list(list_to_print=all_source_columns, columns_to_escape=columns_to_escape) if all_source_columns else " *" }}

    FROM {{ source_relation }}
    {%- set last_cte = "source_data" %}
)

{%- if automate_dv.is_something(derived_columns) -%},

derived_columns AS (

    SELECT

    {{ automate_dv.derive_columns(source_relation=source_relation, columns=derived_columns) | indent(4) }}

    FROM {{ last_cte }}
    {%- set last_cte = "derived_columns" -%}
    {%- set final_columns_to_select = final_columns_to_select + derived_column_names %}
)
{%- endif -%}

{% if automate_dv.is_something(null_columns) -%},

null_columns AS (

    SELECT

    {{ automate_dv.print_list(list_to_print=derived_columns_to_select, columns_to_escape=columns_to_escape) }}{{"," if automate_dv.is_something(derived_columns_to_select) else ""}}

    {{ automate_dv.null_columns(source_relation=none, columns=null_columns) | indent(4) }}

    FROM {{ last_cte }}
    {%- set last_cte = "null_columns" -%}
    {%- set final_columns_to_select = final_columns_to_select + null_column_names %}
)
{%- endif -%}


{% if automate_dv.is_something(hashed_columns) -%},

hashed_columns AS (

    SELECT

    {{ automate_dv.print_list(list_to_print=derived_and_null_columns_to_select, columns_to_escape=columns_to_escape) }},

    {% set processed_hash_columns = automate_dv.process_hash_column_excludes(hashed_columns, all_source_columns) -%}
    {{- automate_dv.hash_columns(columns=processed_hash_columns, columns_to_escape=columns_to_escape) | indent(4) }}

    FROM {{ last_cte }}
    {%- set last_cte = "hashed_columns" -%}
    {%- set final_columns_to_select = final_columns_to_select + hashed_column_names %}
)
{%- endif -%}

{% if automate_dv.is_something(ranked_columns) -%},

ranked_columns AS (

    SELECT *,

    {{ automate_dv.rank_columns(columns=ranked_columns) | indent(4) if automate_dv.is_something(ranked_columns) }}

    FROM {{ last_cte }}
    {%- set last_cte = "ranked_columns" -%}
    {%- set final_columns_to_select = final_columns_to_select + ranked_column_names %}
)
{%- endif -%}

,

columns_to_select AS (

    SELECT

    {{ automate_dv.print_list(list_to_print=final_columns_to_select | unique | list, columns_to_escape=columns_to_escape) }}

    FROM {{ last_cte }}
)

SELECT * FROM columns_to_select

{%- endmacro -%}

macro.automate_dv.bridge_overlap_and_new.macro_sql:
{%- macro bridge_overlap_and_new_rows(src_pk, bridge_walk, source_model, new_as_of_dates_cte) -%}

SELECT
    {{ automate_dv.prefix([src_pk], 'a') }},
    b.AS_OF_DATE,
    {%- for bridge_step in bridge_walk.keys() -%}
        {%- set link_table = bridge_walk[bridge_step]['link_table'] -%}
        {%- set eff_sat_table = bridge_walk[bridge_step]['eff_sat_table'] -%}

        {%- set link_pk = bridge_walk[bridge_step]['link_pk'] -%}

        {%- set bridge_link_pk = bridge_walk[bridge_step]['bridge_link_pk'] -%}
        {%- set bridge_end_date = bridge_walk[bridge_step]['bridge_end_date'] -%}
        {%- set bridge_load_date = bridge_walk[bridge_step]['bridge_load_date'] -%}

        {%- set eff_sat_end_date = bridge_walk[bridge_step]['eff_sat_end_date'] -%}
        {%- set eff_sat_load_date = bridge_walk[bridge_step]['eff_sat_load_date'] %}

        {{- '\n   ' }} {{ link_table | lower }}.{{ link_pk }} AS {{ bridge_link_pk }},
        {{- '\n   ' }} {{ eff_sat_table | lower }}.{{ eff_sat_end_date }} AS {{ bridge_end_date }},
        {{- '\n   ' }} {{ eff_sat_table | lower }}.{{ eff_sat_load_date }} AS {{ bridge_load_date }}

        {%- if not loop.last %}, {%- endif -%}

    {% endfor %}

    FROM {{ source_model }} AS a
    INNER JOIN {{ new_as_of_dates_cte }} AS b
        ON (1=1)

    {%- set loop_vars = namespace(last_link = '', last_link_fk = '') %}
    {%- for bridge_step in bridge_walk.keys() -%}

        {%- set current_link = bridge_walk[bridge_step]['link_table'] -%}
        {%- set current_eff_sat = bridge_walk[bridge_step]['eff_sat_table'] -%}

        {%- set link_pk = bridge_walk[bridge_step]['link_pk'] -%}
        {%- set link_fk1 = bridge_walk[bridge_step]['link_fk1'] -%}
        {%- set link_fk2 = bridge_walk[bridge_step]['link_fk2'] -%}

        {%- set eff_sat_pk = bridge_walk[bridge_step]['eff_sat_pk'] -%}
        {%- set eff_sat_load_date = bridge_walk[bridge_step]['eff_sat_load_date'] -%}

    {%- if loop.first %}
    LEFT JOIN {{ ref(current_link) }} AS {{ current_link | lower }}
        ON {{ automate_dv.multikey(src_pk, prefix=['a', current_link | lower], condition='=') }}
    {%- else %}
    LEFT JOIN {{ ref(current_link) }} AS {{ current_link | lower }}
        ON {{ loop_vars.last_link }}.{{ loop_vars.last_link_fk2 }} = {{ current_link | lower }}.{{ link_fk1 }}
    {%- endif %}
    INNER JOIN {{ ref(current_eff_sat) }} AS {{ current_eff_sat | lower }}
        ON {{ current_eff_sat | lower }}.{{ eff_sat_pk }} = {{ current_link | lower }}.{{ link_pk }}
        AND {{ current_eff_sat | lower }}.{{ eff_sat_load_date }} <= b.AS_OF_DATE
        {%- set loop_vars.last_link = current_link | lower -%}
        {%- set loop_vars.last_link_fk2 = link_fk2 -%}
    {% endfor %}

{%- endmacro -%}

macro.automate_dv.as_of_date_window.macro_sql:
{%- macro as_of_date_window(src_pk, src_ldts, stage_tables_ldts, source_model) -%}

last_safe_load_datetime AS (
    SELECT MIN(LOAD_DATETIME) AS LAST_SAFE_LOAD_DATETIME
    FROM (

        {% for stg in stage_tables_ldts -%}
            {%- set stage_ldts = stage_tables_ldts[stg] -%}
            SELECT MIN({{ stage_ldts }}) AS LOAD_DATETIME FROM {{ ref(stg) }}
            {% if not loop.last %} UNION ALL {% endif %}
        {% endfor -%}

    ) AS l
),

as_of_grain_old_entries AS (
    SELECT DISTINCT AS_OF_DATE
    FROM {{ this }}
),

as_of_grain_lost_entries AS (
    SELECT a.AS_OF_DATE
    FROM as_of_grain_old_entries AS a
    LEFT OUTER JOIN as_of_dates AS b
        ON a.AS_OF_DATE = b.AS_OF_DATE
    WHERE b.AS_OF_DATE IS NULL
),

as_of_grain_new_entries AS (
    SELECT a.AS_OF_DATE
    FROM as_of_dates AS a
    LEFT OUTER JOIN as_of_grain_old_entries AS b
        ON a.AS_OF_DATE = b.AS_OF_DATE
    WHERE b.AS_OF_DATE IS NULL
),

min_date AS (
    SELECT MIN(AS_OF_DATE) AS MIN_DATE
    FROM as_of_dates
),

backfill_as_of AS (
    SELECT AS_OF_DATE
    FROM as_of_dates AS a

    {% if target.type == "bigquery" -%}
    INNER JOIN last_safe_load_datetime as l
    ON a.AS_OF_DATE < l.LAST_SAFE_LOAD_DATETIME
    {% else %}
    WHERE a.AS_OF_DATE < (SELECT LAST_SAFE_LOAD_DATETIME FROM last_safe_load_datetime)
    {%- endif %}
),

new_rows_pks AS (
    SELECT {{ automate_dv.prefix([src_pk], 'h') }}
    FROM {{ source_model }} AS h

    {% if target.type == "bigquery" -%}
    INNER JOIN last_safe_load_datetime as l
    ON h.{{ src_ldts }} >= l.LAST_SAFE_LOAD_DATETIME
    {% else %}
    WHERE h.{{ src_ldts }} >= (SELECT LAST_SAFE_LOAD_DATETIME FROM last_safe_load_datetime)
    {%- endif %}
),

new_rows_as_of AS (
    SELECT AS_OF_DATE
    FROM as_of_dates AS a
    {% if target.type == "bigquery" -%}
    INNER JOIN last_safe_load_datetime as l
    ON a.AS_OF_DATE >= l.LAST_SAFE_LOAD_DATETIME
    UNION DISTINCT
    {% else %}
    WHERE a.AS_OF_DATE >= (SELECT LAST_SAFE_LOAD_DATETIME FROM last_safe_load_datetime)
    UNION
    {%- endif %}
    SELECT as_of_date
    FROM as_of_grain_new_entries
),

overlap_pks AS (
    SELECT a.*
    FROM {{ this }} AS a
    INNER JOIN {{ source_model }} as b
        ON {{ automate_dv.multikey(src_pk, prefix=['a','b'], condition='=') }}
    {% if target.type == "bigquery" -%}
    INNER JOIN min_date
    ON 1 = 1
    INNER JOIN last_safe_load_datetime
    ON 1 = 1
	LEFT OUTER JOIN as_of_grain_lost_entries
	ON a.AS_OF_DATE = as_of_grain_lost_entries.AS_OF_DATE
    WHERE a.AS_OF_DATE >= min_date.MIN_DATE
        AND a.AS_OF_DATE < last_safe_load_datetime.LAST_SAFE_LOAD_DATETIME
		AND as_of_grain_lost_entries.AS_OF_DATE IS NULL
    {% else %}
    WHERE a.AS_OF_DATE >= (SELECT MIN_DATE FROM min_date)
        AND a.AS_OF_DATE < (SELECT LAST_SAFE_LOAD_DATETIME FROM last_safe_load_datetime)
        AND a.AS_OF_DATE NOT IN (SELECT AS_OF_DATE FROM as_of_grain_lost_entries)
    {%- endif %}
),

overlap_as_of AS (
    SELECT p.AS_OF_DATE
    FROM as_of_dates AS p
    {% if target.type == "bigquery" -%}
    INNER JOIN min_date
    ON 1 = 1
    INNER JOIN last_safe_load_datetime
    ON 1 = 1
	LEFT OUTER JOIN as_of_grain_lost_entries
	ON p.AS_OF_DATE = as_of_grain_lost_entries.AS_OF_DATE
    WHERE p.AS_OF_DATE >= min_date.MIN_DATE
        AND p.AS_OF_DATE < last_safe_load_datetime.LAST_SAFE_LOAD_DATETIME
		AND as_of_grain_lost_entries.AS_OF_DATE IS NULL
    {% else %}
    WHERE p.AS_OF_DATE >= (SELECT MIN_DATE FROM min_date)
        AND p.AS_OF_DATE < (SELECT LAST_SAFE_LOAD_DATETIME FROM last_safe_load_datetime)
        AND p.AS_OF_DATE NOT IN (SELECT AS_OF_DATE FROM as_of_grain_lost_entries)
    {% endif %}
)

{%- endmacro -%}

