            AND {{ sat_name | lower ~ '_src'}}.{{ sat_ldts }} <= a.AS_OF_DATE
    {% endfor %}

    GROUP BY
        {{ automate_dv.prefix([src_pk], 'a') }},
        a.AS_OF_DATE
